import { type PropsWithChildren, type JSX, type ReactNode } from 'react';
import { ErrorBoundary } from 'react-error-boundary';

import { EmptyState } from '../../chart-states/EmptyState.js';
import { ErrorState } from '../../chart-states/ErrorState.js';
import { LoaderOverlay } from '../../loader-overlay/LoaderOverlay.js';
import { LoadingContext } from '../context/Loading.context.js';

interface LayoutStateHandlerProps {
  empty: boolean;
  height: string | number;
  emptyState: ReactNode | undefined;
  errorState: ReactNode | ((message: string) => JSX.Element) | undefined;
  showLoader: boolean;
}
export const LayoutStateHandler = (
  props: PropsWithChildren<LayoutStateHandlerProps>,
) => {
  const { children, empty, emptyState, errorState, height, showLoader } = props;

  if (empty) {
    return showLoader ? (
      <LoaderOverlay />
    ) : (
      <EmptyState height={height}>{emptyState}</EmptyState>
    );
  }

  return (
    <ErrorBoundary
      FallbackComponent={ErrorState({
        height: height,
        children: errorState,
      })}
    >
      <LoadingContext.Provider value={showLoader}>
        {children}
      </LoadingContext.Provider>
      {showLoader && <LoaderOverlay gridArea="1/1/2/2" />}
    </ErrorBoundary>
  );
};
